import React from 'react';

import TradeForm from './TradeForm';
import TradeList from './TradeList';



function Trades() {
    const trades = [
        {id:'ID', stock:'STK', method:'Method', quantity:'Q', profitLoss:'P'},
        {id:1, stock:'MES', method:'Bollinger', quantity:1, profitLoss:1},
        {id:2, stock:'MES', method:'--S & R--', quantity:2, profitLoss:3}
    ]

    return(
        <div>
            <TradeForm trades={trades} />
            <TradeList trades={trades}/>
        </div>    
    )
}

export default Trades;
